import base64, os

FILES = {
    "components/SpinToWinPanel.tsx": """""",
    "app/host/quiz/page.tsx": """""",
    "supabase/sql/spin_used.sql": """YWx0ZXIgdGFibGUgcHVibGljLnNlc3Npb25zIGFkZCBjb2x1bW4gaWYgbm90IGV4aXN0cyBzcGluX3VzZWQgYm9vbGVhbiBkZWZhdWx0IGZhbHNlOwo=""",
}


for path, b64 in FILES.items():
    d = os.path.dirname(path)
    if d:
        os.makedirs(d, exist_ok=True)
    with open(path, "wb") as f:
        f.write(base64.b64decode(b64))
    print("Written:", path)
print("All Spin to Win files written successfully")
